private func zoomStatusMode(for zoom: CGFloat? = nil) -> ZoomStatusMode {
    let currentZoom = zoom ?? scrollView.magnification
    let windowAuto = !settings.continuousScrollEnabled && shouldResizeWindowToMatchImage()

    if isAutoFitActive {
